import{g as e,m as t,n}from"./index-8qbH6X9N.js";import{t as r}from"./PageBanner-BFLQJemA.js";import{t as i}from"./SectionTitle-Cv7fOt23.js";import{t as a}from"./aboutService-zVXiCrS4.js";var o=e(t(),1),s={hero:{title:`About Jamia Tul Uloom Muhammadiya`,description:`Preserving authentic Islamic knowledge through modern education since 1998.`},intro:{title:`Our Story`,subtitle:`Who We Are`,paragraphs:[`Jamia Tul Uloom Muhammadiya was established in 1998 with a singular vision — to provide authentic Islamic education rooted in the Quran and Sunnah, delivered with modern pedagogical excellence. What began as a small Madrasa in Karachi has grown into a globally recognized online Islamic academy serving students across 45+ countries.`,`Our curriculum spans the full spectrum of Islamic sciences: Quranic recitation with Tajweed, Hifz-ul-Quran, Tafseer, Arabic language, and comprehensive Islamic studies. Every course is taught by qualified scholars holding Ijazah from prestigious institutions including Madinah University, Al-Azhar University, and Umm al-Qura University.`,`We believe that Islamic education should be accessible to everyone regardless of geographical location, age, or background. Our online platform breaks down barriers, bringing qualified teachers directly into your home through live interactive classes.`,`Today, with over 5,000 enrolled students and 120 qualified teachers, we remain committed to our founding mission: nurturing a generation of Muslims who understand their faith deeply and practice it with confidence.`],imageLabel:`Since 1998`},mission:{title:`Our Mission`,description:`To provide accessible, authentic, and high-quality Islamic education to students worldwide through innovative online learning platforms, preserving traditional scholarship while embracing modern technology.`,icon:`mission`},vision:{title:`Our Vision`,description:`To become the world's most trusted online Islamic academy, producing thousands of knowledgeable, practicing Muslims who contribute positively to their communities and uphold the teachings of the Quran and Sunnah.`,icon:`vision`},coreValues:[{id:1,title:`Integrity`,description:`Upholding honesty and moral principles in every aspect of education and administration.`,icon:`integrity`},{id:2,title:`Knowledge`,description:`Pursuing authentic Islamic knowledge with depth, accuracy, and continuous learning.`,icon:`knowledge`},{id:3,title:`Compassion`,description:`Treating every student with kindness, patience, and genuine care for their spiritual growth.`,icon:`compassion`},{id:4,title:`Discipline`,description:`Maintaining structured learning paths with consistent dedication and academic rigor.`,icon:`discipline`},{id:5,title:`Excellence`,description:`Striving for the highest standards in teaching, curriculum, and student experience.`,icon:`excellence`},{id:6,title:`Faith`,description:`Grounding everything we do in sincere devotion to Allah and love for His Messenger.`,icon:`faith`}],timeline:[{year:`1998`,title:`Foundation`,description:`Jamia Tul Uloom Muhammadiya was established in Karachi as a traditional Madrasa for Quranic and Islamic studies.`},{year:`2005`,title:`Expansion & Growth`,description:`Expanded facilities, added new courses, and increased student capacity. Recognized as a leading Islamic institution.`},{year:`2015`,title:`Online Academy Launch`,description:`Launched our online learning platform, making Islamic education accessible to students worldwide.`},{year:`2020`,title:`Global Recognition`,description:`Reached 2,000+ international students from 30+ countries. Introduced Ijazah programs with certified scholars.`},{year:`2024`,title:`International Excellence`,description:`5,000+ students, 120+ teachers, 45+ countries. Advanced digital platform with live classes and recorded lectures.`},{year:`2026`,title:`Future Vision`,description:`Continuing to expand our reach, enhance our curriculum, and develop innovative learning tools for the global Muslim community.`}],founder:{name:`Maulana Muhammad Yusuf Rahmani`,title:`Founder & Principal`,qualification:`PhD in Islamic Studies, Darul Uloom Deoband`,experience:`35+ years`,message:`Education is the foundation of a strong Muslim Ummah. At Jamia Tul Uloom Muhammadiya, we have dedicated our lives to preserving and transmitting authentic Islamic knowledge. Our goal is not just to teach, but to nurture character, build faith, and prepare our students to be leaders in their communities. I invite you to join us on this blessed journey of seeking knowledge.`,signature:`Maulana Muhammad Yusuf Rahmani`},facilities:[{id:1,title:`Modern Virtual Classrooms`,description:`State-of-the-art interactive classrooms with real-time audio, video, and screen sharing capabilities.`,icon:`classroom`},{id:2,title:`Digital Islamic Library`,description:`Comprehensive digital library with thousands of Islamic texts, Tafseer collections, and academic references.`,icon:`library`},{id:3,title:`Male & Female Sections`,description:`Separate learning environments with male and female teachers available for your comfort and preference.`,icon:`gender`},{id:4,title:`24/7 Learning Portal`,description:`Access recorded lectures, assignments, and study materials anytime through our dedicated student portal.`,icon:`online`},{id:5,title:`On-Campus Facilities`,description:`Masjid, hostel accommodation, and dedicated study areas available for residential students in Karachi.`,icon:`campus`},{id:6,title:`Student Support System`,description:`Dedicated academic advisors and technical support available 24/7 to assist students throughout their journey.`,icon:`support`}],achievements:[{id:1,value:5e3,suffix:`+`,label:`Students Graduated`,icon:`graduation`},{id:2,value:120,suffix:`+`,label:`Qualified Teachers`,icon:`teachers`},{id:3,value:45,suffix:`+`,label:`Countries Worldwide`,icon:`globe`},{id:4,value:15,suffix:`+`,label:`Courses Offered`,icon:`book`},{id:5,value:28,suffix:` Years`,label:`of Educational Excellence`,icon:`years`}]},c=n